import React, { useEffect, useState } from "react";
import FAWInput from "../../../../component-widget/FAWInput";
import FAWDropdown from "../../../../component-widget/FAWDropdown";
import EditorShell from "./shared/EditorShell";
import BaseQuestionFields from "./shared/BaseQuestionFields";
import EditorSection from "./shared/EditorSection";
import FAWCloningOptions from "./shared/FAWCloningOptions";

export default function QueCustomValueSelectorItemEditor({ data, onSave, onClose, saveRef, isDefaultLanguage = true, availableSelectionPages = [] }) {
  const [item, setItem] = useState(
    data || { 
      name: "", 
      text: "", 
      required: false, 
      validationMessage: "", 
      horizontalLine: false, 
      selectionPage: "",
      cloningOptions: {}
    }
  );
  
  useEffect(()=>{ if (data) setItem(prev=>({ ...prev, ...data })); }, [data]);
  const handleChange = (field, value) => setItem(prev=>({ ...prev, [field]: value }));
  const handleSave = () => { 
    onSave?.(item); 

  };
  
  const selectionOptions = (availableSelectionPages || []).map(p => ({ label: p.label || p.Text || String(p), value: p.value || p.Value || String(p) }));

  return (
    <EditorShell onSave={handleSave} onClose={onClose} saveRef={saveRef}>
      <BaseQuestionFields item={item} onChange={setItem} isDefaultLanguage={isDefaultLanguage} questionType="CustomValueSelectorItemType" />
      
      <EditorSection title="Selection">
        <FAWDropdown 
          label="Value Selection Page" 
          value={item.selectionPage}
          options={selectionOptions}
          onChange={(opt)=>handleChange('selectionPage', opt?.value || "")}
          fullWidth
          placeholder="Select a page"
        />
      </EditorSection>

      <hr />
      <FAWCloningOptions 
        data={item.cloningOptions} 
        onChange={(data) => handleChange("cloningOptions", data)}
      />
    </EditorShell>
  );
}



